-- ----------------------------
-- Table structure for qrtz_triggers
-- ----------------------------
DROP TABLE IF EXISTS `qrtz_triggers`;
CREATE TABLE `qrtz_triggers` (
  `sched_name` varchar(120) NOT NULL COMMENT '调度名称',
  `trigger_name` varchar(200) NOT NULL COMMENT '触发器的名字',
  `trigger_group` varchar(200) NOT NULL COMMENT '触发器所属组的名字',
  `job_name` varchar(200) NOT NULL COMMENT 'qrtz_job_details表job_name的外键',
  `job_group` varchar(200) NOT NULL COMMENT 'qrtz_job_details表job_group的外键',
  `description` varchar(250) DEFAULT NULL COMMENT '相关介绍',
  `next_fire_time` bigint(13) DEFAULT NULL COMMENT '上一次触发时间（毫秒）',
  `prev_fire_time` bigint(13) DEFAULT NULL COMMENT '下一次触发时间（默认为-1表示不触发）',
  `priority` int(11) DEFAULT NULL COMMENT '优先级',
  `trigger_state` varchar(16) NOT NULL COMMENT '触发器状态',
  `trigger_type` varchar(8) NOT NULL COMMENT '触发器的类型',
  `start_time` bigint(13) NOT NULL COMMENT '开始时间',
  `end_time` bigint(13) DEFAULT NULL COMMENT '结束时间',
  `calendar_name` varchar(200) DEFAULT NULL COMMENT '日程表名称',
  `misfire_instr` smallint(2) DEFAULT NULL COMMENT '补偿执行的策略',
  `job_data` blob COMMENT '存放持久化job对象',
  PRIMARY KEY (`sched_name`,`trigger_name`,`trigger_group`),
  KEY `sched_name` (`sched_name`,`job_name`,`job_group`),
  CONSTRAINT `qrtz_triggers_ibfk_1` FOREIGN KEY (`sched_name`, `job_name`, `job_group`) REFERENCES `qrtz_job_details` (`sched_name`, `job_name`, `job_group`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='触发器详细信息表';

-- ----------------------------
-- Records of qrtz_triggers
-- ----------------------------

-- ----------------------------
-- Table structure for running_routes
-- ----------------------------
DROP TABLE IF EXISTS `running_routes`;
CREATE TABLE `running_routes` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `route_name` varchar(100) NOT NULL COMMENT '路线名称',
  `route_img` varchar(255) DEFAULT NULL COMMENT '路线图片URL',
  `distance_km` decimal(10,2) NOT NULL COMMENT '公里数，带2位小数',
  `runners` int(10) unsigned DEFAULT '0' COMMENT '跑过人数',
  `start_dist_km` decimal(10,2) DEFAULT '0.00' COMMENT '起点距您公里数',
  `category` enum('公园路线','街道路线') NOT NULL COMMENT '路线分类',
  `exact_starting_address` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_category` (`category`),
  KEY `idx_start_dist` (`start_dist_km`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='跑步路线列表';

-- ----------------------------
-- Records of running_routes
-- ----------------------------

-- ----------------------------
-- Table structure for running_route_favorite_status
-- ----------------------------
DROP TABLE IF EXISTS `running_route_favorite_status`;
CREATE TABLE `running_route_favorite_status` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `userid` int(11) DEFAULT NULL COMMENT '用户id',
  `route_id` int(11) DEFAULT NULL COMMENT '路线id',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=5 DEFAULT CHARSET=utf8 COMMENT='路线收藏状态';

-- ----------------------------
-- Records of running_route_favorite_status
-- ----------------------------

-- ----------------------------
-- Table structure for sleep_data
-- ----------------------------
DROP TABLE IF EXISTS `sleep_data`;
CREATE TABLE `sleep_data` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '唯一标识',
  `record_date` date NOT NULL COMMENT '记录日期',
  `total_sleep_time` time NOT NULL COMMENT '总睡眠时间',
  `deep_sleep_time` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '深睡眠时间',
  `light_sleep_time` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '浅睡眠时间',
  `rem_sleep_time` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '快速眼动睡眠时间',
  `average_heart_rate` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '平均心率',
  `average_oxygen_saturation` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '平均血氧饱和度',
  `average_breathing_rate` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '平均呼吸率',
  `sleep_quality_score` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '睡眠质量评分',
  `userid` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=39 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='睡眠数据表';

-- ----------------------------
-- Records of sleep_data
-- ----------------------------

-- ----------------------------
-- Table structure for sport_team
-- ----------------------------
DROP TABLE IF EXISTS `sport_team`;
CREATE TABLE `sport_team` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT COMMENT '主键',
  `avatar` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '团队头像URL（正方形）',
  `team_name` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '团队名称',
  `member_count` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '0' COMMENT '团队人数',
  `category` enum('跑步','健走','跑走','骑行','健身') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '团队分类',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `lowerCamelase` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `toralSportsTime` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `totalConsumption` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `tasKTime` datetime DEFAULT NULL,
  `taskday` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `content` varchar(2550) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_category` (`category`)
) ENGINE=InnoDB AUTO_INCREMENT=29 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='运动团队列表';

-- ----------------------------
-- Records of sport_team
-- ----------------------------

-- ----------------------------
