  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `workout_time` datetime NOT NULL COMMENT '运动开始时间（HH:MM:SS）',
  `category` enum('室内跑步','户外跑步','健走','户外骑行','泳池游泳','自由活动') NOT NULL COMMENT '运动分类',
  `calories` decimal(6,2) NOT NULL COMMENT '消耗卡路里（千卡，可小数）',
