DROP EVENT IF EXISTS `del_expired_captcha`;
DELIMITER ;;
CREATE DEFINER=`lian`@`localhost` EVENT `del_expired_captcha` ON SCHEDULE EVERY 1 DAY STARTS '2026-01-06 03:00:00' ON COMPLETION NOT PRESERVE ENABLE DO DELETE FROM `captcha` WHERE `expire_at` < NOW()
;;
DELIMITER ;
